CREATE TYPE commodity_type AS ENUM ('CIGARETTES','COMAT','DRY_CARGO','ELECTRONICS','EMPTY_BAGS','EMPTY_PALLET','EMPTY_ULD','FCC','GENERAL','HIGH_VALUES','LIVE_PLANTS','NETS','PERISHABLE','RED_TAG','SDQ_MIA','SDQ_SDF','SMALL_PACKAGES','WWEF');
CREATE TYPE aircraft_type AS ENUM ('A300','A310','A330','B727','B737','B747','B757','B767','B777','DC8','MD11','OTHER');
CREATE TYPE flight_status AS ENUM ('ARRIVED','BOARDING','CANCELLED','DELAYED','DEPARTED','SCHEDULED');
CREATE TYPE mawb_status AS ENUM ('ARRIVED','BOOKED','CANCELLED','DEPARTED','MANIFESTED','RECEIVED');
CREATE TYPE uld_status AS ENUM ('BUILT','LOADED','OFFLOADED','OPEN','SEALED');
CREATE TYPE uld_type AS ENUM ('AAD','AAY','AAZ','AMJ','AMP','BULK','PAG','PAH','PAJ','PIP','PMC');
CREATE TYPE user_role AS ENUM ('ADMIN','OPERATIONS','WAREHOUSE','READ_ONLY');

CREATE TABLE airline (id uuid NOT NULL, code varchar(10) NOT NULL, country varchar(60), created_at timestamptz NOT NULL, iata_code varchar(3), is_active boolean NOT NULL, name varchar(100) NOT NULL, updated_at timestamptz NOT NULL, PRIMARY KEY (id), CONSTRAINT UKtm8b09a7lmd7f9nlhu18ksvue UNIQUE (code));
CREATE TABLE app_user (id uuid NOT NULL, created_at timestamptz NOT NULL, email varchar(200) NOT NULL, full_name varchar(150), is_active boolean NOT NULL, last_login timestamptz, role user_role NOT NULL, supabase_uid uuid, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, PRIMARY KEY (id), CONSTRAINT UK1j9d9a06i600gd43uu3km82jw UNIQUE (email));
CREATE TABLE flight (id uuid NOT NULL, aircraft_reg varchar(20), aircraft_type aircraft_type, created_at timestamptz NOT NULL, destination char(3) NOT NULL, flight_date date NOT NULL, flight_number varchar(20) NOT NULL, max_payload_kg numeric(10,2), notes varchar(255), origin char(3) NOT NULL, status flight_status NOT NULL, total_positions integer, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, PRIMARY KEY (id), CONSTRAINT flight_airline_id_flight_number_flight_date_key UNIQUE (airline_id, flight_number, flight_date));
CREATE TABLE mawb (id uuid NOT NULL, awb_number varchar(20) NOT NULL, booked_in_acoms boolean, cash_only boolean, chargeable_weight_kg numeric(10,2), commodity_type commodity_type NOT NULL, consignee_name varchar(150), created_at timestamptz NOT NULL, customs_completed boolean, destination char(3) NOT NULL, docs_provided boolean, loose_tender boolean, notes varchar(255), origin char(3) NOT NULL, pieces integer NOT NULL, pre_built boolean, reported_weight_kg numeric(10,2), shipper_name varchar(150), status mawb_status NOT NULL, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, flight_id uuid, PRIMARY KEY (id));
CREATE TABLE booking (id uuid NOT NULL, awb_number varchar(20), client_name varchar(150) NOT NULL, cnee varchar(150), commodity_type commodity_type NOT NULL, confirmed_kg numeric(10,3), contact_name varchar(100) NOT NULL, created_at timestamptz NOT NULL, day_received varchar(5), destination char(3), fulfillment_pct numeric(6,4), is_confirmed boolean, last_week_kg numeric(10,3), last_week_positions numeric(8,4), notes varchar(255), positions numeric(8,4), priority integer, real_positions numeric(8,4), received_kg numeric(10,3), reserved_kg numeric(10,3) NOT NULL, shipper_name varchar(150), skids integer, time_hours numeric(6,4), units integer, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, flight_id uuid NOT NULL, mawb_id uuid, PRIMARY KEY (id));
CREATE TABLE hawb (id uuid NOT NULL, commodity_type commodity_type, consignee_name varchar(150), created_at timestamptz NOT NULL, destination char(3), hawb_number varchar(30) NOT NULL, notes varchar(255), pieces integer NOT NULL, status mawb_status NOT NULL, updated_at timestamptz NOT NULL, weight_kg numeric(10,2), airline_id uuid NOT NULL, mawb_id uuid NOT NULL, PRIMARY KEY (id));
CREATE TABLE uld (id uuid NOT NULL, built_at timestamptz, config varchar(10), created_at timestamptz NOT NULL, gross_weight_kg numeric(10,2), gross_weight_lbs numeric(10,2) NOT NULL, loaded_at timestamptz, net_weight_kg numeric(10,2), net_weight_lbs numeric(10,2), notes varchar(255), position varchar(10), seal_number varchar(50), status uld_status NOT NULL, tare_kg numeric(10,2), tare_lbs numeric(8,2) NOT NULL, tare_notes varchar(200), uld_number varchar(30) NOT NULL, uld_type uld_type NOT NULL, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, flight_id uuid NOT NULL, PRIMARY KEY (id));
CREATE TABLE uld_awb (id uuid NOT NULL, avg_time_per_piece_sec integer, comments varchar(255), consumption_pallets numeric(6,3), created_at timestamptz, description commodity_type NOT NULL, destination char(3), end_time time, hc boolean, mawb_label varchar(50), pieces integer, pieces_pct integer, start_time time, temp_inbound numeric(6,2), temp_outbound numeric(6,2), mawb_id uuid, uld_id uuid NOT NULL, PRIMARY KEY (id));
CREATE TABLE uld_type_config (id uuid NOT NULL, created_at timestamptz NOT NULL, default_tare_lbs numeric(8,2) NOT NULL, max_gross_lbs numeric(10,2), notes varchar(255), uld_type uld_type NOT NULL, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, PRIMARY KEY (id));
CREATE TABLE warehouse_receipt (id uuid NOT NULL, actual_weight_kg numeric(10,3), actual_weight_lbs numeric(10,3), agent_name varchar(150), awb_reported_pieces integer, booked_in_acoms boolean, broker_id_doc_url varchar(255), broker_id_num varchar(50), broker_name varchar(150), broker_sig_url varchar(255), cash_only boolean, chargeable_weight_kg numeric(10,3), chargeable_weight_lbs numeric(10,3), consignee_name varchar(150), created_at timestamptz NOT NULL, created_by_name varchar(150), customs_completed boolean, delivered_by_id_doc_url varchar(255), delivered_by_id_num varchar(50), delivered_by_name varchar(150), delivered_by_sig_url varchar(255), destination char(3), dim_factor_dom numeric(6,0), dim_factor_intl numeric(6,0), dock_signature varchar(150), docs_provided boolean, gateway_cfs varchar(10), loose_tender boolean, mawb_weight_greatest numeric(10,3), observations varchar(255), origin char(3), piece_count integer, pre_built boolean, print_name varchar(150), receipt_date timestamptz, receipt_doc_url varchar(255), received_by_id_doc_url varchar(255), received_by_id_num varchar(50), received_by_name varchar(150), received_by_sig_url varchar(255), remarks varchar(255), shipper_comment varchar(255), shipper_name varchar(150), shipper_reported_weight numeric(10,3), start_datetime timestamptz, updated_at timestamptz NOT NULL, airline_id uuid NOT NULL, created_by_user_id uuid, mawb_id uuid NOT NULL, PRIMARY KEY (id));
CREATE TABLE receipt_piece (id uuid NOT NULL, chargeable_kg numeric(10,3), chargeable_lbs numeric(10,3), dim_weight_kg numeric(10,3), dim_weight_lbs numeric(10,3), height_in numeric(8,2), length_in numeric(8,2), piece_number integer NOT NULL, scale_weight_kg numeric(10,3), scale_weight_lbs numeric(10,3), width_in numeric(8,2), receipt_id uuid NOT NULL, PRIMARY KEY (id));

